h1 { color: red; }                 /* element */
.highlight { color: pink; }         /* class beats element */
.highlight.now { color: brown; }    /* two classes beat one */
#title { color: green; }            /* id beats classes */
/* style="color: blue" — inline wins over id */
/* color: purple !important; — overrides normal specificity */

/* Removed from layout + usually from a11y tree */
.gone { display: none; }
<p hidden>Also hidden</p>

/* Invisible but may still take space / differ for a11y */
.invisible { visibility: hidden; }
.transparent { opacity: 0; }

/* Visually hidden, still available to screen readers */
.sr-only {
  position: absolute;
  width: 1px;
  height: 1px;
  overflow: hidden;
  clip: rect(0, 0, 0, 0);
}

.card {
  width: 200px;           /* content width (with content-box) */
  padding: 16px;          /* inside the border */
  border: 2px solid #333;
  margin: 24px;           /* outside the border */
}

/* Total outer size depends on box-sizing */

*, *::before, *::after {
  box-sizing: border-box;
}

.box {
  width: 200px;
  padding: 20px;
  border: 5px solid black;
  /* total rendered width stays 200px with border-box */
}

/* Pseudo-class — element state */
a:hover {
  color: #ff00ff;
}

/* Pseudo-element — part / generated content */
p::first-line {
  text-transform: uppercase;
}

.btn::before {
  content: '→ ';
}

/* Mobile base styles here... */

@media screen and (min-width: 768px) {
  .layout {
    display: grid;
    grid-template-columns: 240px 1fr;
  }
}

@media print {
  .no-print { display: none; }
}

.media img {
  float: left;
  margin-right: 1rem;
}

/* Prevent parent height collapse */
.clearfix::after {
  content: '';
  display: block;
  clear: both;
}

/* Flexbox — 1D alignment */
.nav {
  display: flex;
  justify-content: space-between;
  align-items: center;
  gap: 1rem;
}

/* Grid — 2D layout */
.page {
  display: grid;
  grid-template-columns: 240px 1fr;
  grid-template-rows: auto 1fr auto;
  gap: 1rem;
}

/* Base = mobile */
.card {
  padding: 1rem;
}

/* Enhance for larger screens */
@media (min-width: 768px) {
  .card {
    padding: 2rem;
    display: grid;
    grid-template-columns: 1fr 1fr;
  }
}

/* Reset-style — aggressive blank slate */
* {
  margin: 0;
  padding: 0;
  box-sizing: border-box;
}

/* Normalize idea — keep useful defaults, fix inconsistencies */
/* e.g. consistent font-size on headings, line-height, form controls */
html {
  line-height: 1.15;
}

/* Prefer classes, flat selectors, clear names */
.btn { }
.btn--primary { }
.card__title { }

/* Avoid */
/* #app div.wrapper > ul li a span { color: red !important; } */

:root {
  --color-primary: #7c3aed;
}
.btn--primary {
  background: var(--color-primary);
}

div {
  display: block;   /* new line, full width, width/height work */
}

span {
  display: inline;  /* same line, content width, width/height ignored */
}

/* Force either behavior when needed */
.badge { display: inline-block; } /* inline flow + box model sizing */
